var DealPlyFingerprintCls;

var DealPlyFingerprint;

if(typeof DealPlyFingerprintCls === "undefined") {
	DealPlyFingerprintCls = function() {};
	
	DealPlyFingerprint = new DealPlyFingerprintCls();
	
	DealPlyFingerprintCls.prototype.getFingerprintForDomainName = function(dealplyDomain) {
		var dealplyDomainDigest = DealPlyStandaloneDomains.digestForString(dealplyDomain.toLowerCase());
		
		return DealPlyFingerprint.getFingerprintForInt(dealplyDomainDigest);
	};
	
	DealPlyFingerprintCls.prototype.getFingerprintForInt = function(dealplyInt) {
	    var prefix = "p";
	    if(dealplyInt < 0) {
	    	prefix = "n";
	    }
	    
	    dealplyInt = Math.abs(dealplyInt);

	    var dealplyS = prefix + dealplyInt.toString(16);
	    
		var digits = "0123456789";
		var chars = "qrstuvwxyz";
		var buf = "";
		for(var i = 0; i < dealplyS.length; i++) {
			var orig = dealplyS.charAt(i);
			var pos = digits.indexOf(orig);
			if(pos > -1) {
				buf += chars.charAt(pos);
			} else {
				buf += orig;
			}
		}
	    
	    return buf;
	};
	
	DealPlyFingerprintCls.prototype.getIntForFingerprint = function(dealplyFingerprint) {
		var positive = true;
		if(dealplyFingerprint.indexOf("n") === 0) {
			positive = false;
		}

		var dealplyS = dealplyFingerprint.substring(1);
		
		var digits = "0123456789";
		var chars = "qrstuvwxyz";
		var buf = "";
		for(var i = 0; i < dealplyS.length; i++) {
			var orig = dealplyS.charAt(i);
			var pos = chars.indexOf(orig);
			if(pos > -1) {
				buf += digits.charAt(pos);
			} else {
				buf += orig;
			}
		}
	    
	    var out = parseInt(buf, 16);

	    if(positive == false) {
	    	out = 0 - out;
	    }
	    
	    return out;
	};
}

function DealPlyStandaloneDomainsCls() {};

var DealPlyStandaloneDomains = new DealPlyStandaloneDomainsCls();

DealPlyStandaloneDomainsCls.prototype.domains = null;

DealPlyStandaloneDomainsCls.prototype.digestForString = function(s){
	var hash = 0;
	if (s.length === 0) {
		return hash;
	}
	
	var char = null;
	
	for (i = 0; i < s.length; i++) {
		char = s.charCodeAt(i);

		hash = 31 * hash+char;
		hash = hash & hash;
	}
	
	return hash;
};

DealPlyStandaloneDomainsCls.prototype.getDomainName = function(host) {
	var array = host.split('.');
	var length = array.length;
	var end = array[length - 1];
	var domain = "";
	if (end === 'com' || end === 'org' || end === 'gov' || end === 'edu'
			|| end === 'info' || end === 'net' || end === 'co') {
		domain = array[length - 2] + '.' + array[length - 1];
	} else {
		beforend = array[length - 2];
		if (beforend === 'co' || beforend === 'com' || beforend === 'org'
				|| beforend === 'gov' || beforend === 'edu'
				|| beforend === 'info' || beforend === 'net') {
			domain = array[length - 3] + '.' + array[length - 2] + '.'
					+ array[length - 1];
		} else {
			domain = array[length - 2] + '.' + array[length - 1];
		}
	}
	return domain;
};

DealPlyStandaloneDomainsCls.prototype.hostFromUrl = function(url) {
	var result = url;
	try {
		result = url.match(/:\/\/(.[^/]+)/)[1];
	} catch (e) {
	}
	return result;
};

DealPlyStandaloneDomainsCls.prototype.isCommerceUrl = function(url) {
	var hostName = DealPlyStandaloneDomains.hostFromUrl(url);
	var domainName = DealPlyStandaloneDomains.getDomainName(hostName);
	var digest = "" + DealPlyFingerprint.getFingerprintForDomainName(domainName);
	var existing = DealPlyStandaloneDomains.domains[digest];
	
	if(typeof existing === "undefined" || existing === null) {
		return false;
	}
	
	return true;
};



