function DealPlyStandaloneOptCls() {};

var DealPlyStandaloneOpt = new DealPlyStandaloneOptCls();

DealPlyStandaloneOpt.partnerName = "fast";
DealPlyStandaloneOpt.channelName = "fast2";
DealPlyStandaloneOpt.appTitle = decodeURIComponent("");

DealPlyStandaloneOpt.isStartAutomatically = false;

DealPlyStandaloneOptCls.prototype.setPartnerName = function(x) {
	DealPlyStandaloneOpt.partnerName = x;
};

DealPlyStandaloneOptCls.prototype.getPartnerName = function() {
	return DealPlyStandaloneOpt.partnerName;
};

DealPlyStandaloneOptCls.prototype.getChannelName = function() {
	return DealPlyStandaloneOpt.channelName;
};

DealPlyStandaloneOptCls.prototype.getAppTitle = function() {
	return DealPlyStandaloneOpt.appTitle;
};

DealPlyStandaloneOptCls.prototype.isFirefox = function() {
	if (typeof navigator.userAgent === "undefined") {
		return false;
	}

	if (navigator.userAgent === null) {
		return false;
	}

	if (navigator.userAgent.toLowerCase().indexOf('firefox') > -1) {
		return true;
	}

	if (navigator.userAgent.toLowerCase().indexOf('opera') > -1) {
		return true;
	}
	
	return false;
};

DealPlyStandaloneOptCls.prototype.isChrome = function() {
	if (typeof navigator.userAgent === "undefined") {
		return false;
	}

	if (navigator.userAgent === null) {
		return false;
	}

	if (navigator.userAgent.toLowerCase().indexOf('chrome') > -1) {
		return true;
	}

	if (navigator.userAgent.toLowerCase().indexOf('apple') > -1 && navigator.userAgent.toLowerCase().indexOf('safari') > -1) {
		return true;
	}
	
	return false;
};

DealPlyStandaloneOptCls.prototype.isIe = function() {
	if (typeof navigator.userAgent === "undefined") {
		return false;
	}

	if (navigator.userAgent === null) {
		return false;
	}

	if (navigator.userAgent.toLowerCase().indexOf('msie') > -1) {
		return true;
	}

	return false;
};

DealPlyStandaloneOptCls.prototype.getRandomGuid = function() {
	dealplyRandId = "";
	var dealplyI = 0;
	for(dealplyI = 0; dealplyI < 18; dealplyI++) {
		dealplyRandDigit = Math.floor(Math.random() * 10);
		
		dealplyRandId = dealplyRandId + dealplyRandDigit;
	}
	
	return dealplyRandId;
};

DealPlyStandaloneOptCls.prototype.getVehicle = function() {
	return "opt";
};

DealPlyStandaloneOptCls.prototype.pushScriptTag = function(src_) {
    try {
	    var newscript = document.createElement("script");
	    var hds_ = document.getElementsByTagName("head");
	    if (hds_ != null) {
		var head = hds_[0];
		if (head != null) {
		    newscript = head.appendChild(newscript);
		    newscript.setAttribute("src", src_);
		}
	    } else {
		var html_ = document.getElementsByTagName("html");
		if (html_ != null) {
		    var hd_new = document.createElement("head");
		    html_.appendChild(hd_new);
		    DealPlyStandaloneOpt.pushScriptTag(src_);
		    return;
		}
	    }
    } catch (e) {

    }
};

DealPlyStandaloneOptCls.prototype.injectDealPlyIntoDocument = function() {
	var partner = DealPlyStandaloneOpt.getPartnerName();

	var mainFrameUrl = document.location.href;

	if(typeof mainFrameUrl === "undefined" || mainFrameUrl === null) {
		return;

	}

	if(mainFrameUrl.toLowerCase().indexOf("google") > -1) {
		return;
	}

	var isCommerceUrl = DealPlyStandaloneDomains.isCommerceUrl(mainFrameUrl);

	if(isCommerceUrl === false) {
		return;
	}

	if(DealPlyStandaloneOpt.isStartAutomatically === false) {
		return;
	}

	var part = DealPlyStandaloneOpt.getInjectedScriptPath();

	if(part === null) {
		return;
	}
	
	var channel = DealPlyStandaloneOpt.getChannelName();

	var vehicle = DealPlyStandaloneOpt.getVehicle();

	if(partner === null) {
		partner = "dealplydef";
	}
	  
	if(channel === null) {
		channel = "dealplydef";
	}
  
	if(document.location.href.toLowerCase().indexOf('http:') !== 0) {
		return;
	
	}
	
	DealPlyConfigLocalCls = function() {

	};

	DealPlyConfigLocal = new DealPlyConfigLocalCls();

	DealPlyConfigLocalCls.prototype.getPartner = function() {
		return DealPlyStandaloneOpt.getPartnerName();
	};
	DealPlyConfigLocalCls.prototype.getChannel = function() {
		return DealPlyStandaloneOpt.getChannelName();
	};
	DealPlyConfigLocalCls.prototype.getAppTitle = function() {
		var appTitle = DealPlyStandaloneOpt.getAppTitle();
		
		if(appTitle === null) {
			appTitle = "";
		}
	  
		return appTitle;
	};
	
	DealPlyConfigLocalCls.prototype.getHardId = function() {
		return null;
	};
	DealPlyConfigLocalCls.prototype.getHardIdSource = function() {
		return null;
	};
	DealPlyConfigLocalCls.prototype.getVehicle = function() {
		return DealPlyStandaloneOpt.getVehicle();
	};

	var scriptSrc = "http://" + part + ".dealply.com/version_content.js";

	DealPlyStandaloneOpt.pushScriptTag(scriptSrc);
};

DealPlyStandaloneOptCls.prototype.getInjectedScriptPath = function() {
	var part = null;

	if(DealPlyStandaloneOpt.isFirefox() === true) {
		part = "firefox";
	}

	if(DealPlyStandaloneOpt.isChrome() === true) {
		part = "chrome";
	}

	if(DealPlyStandaloneOpt.isIe() === true) {
		part = "ie";
	}

	return part;
};

DealPlyStandaloneOptCls.prototype.start = function() {
	DealPlyStandaloneOpt.isStartAutomatically = true;
	
	DealPlyStandaloneOpt.injectDealPlyIntoDocument();
};

DealPlyStandaloneOptCls.prototype.getAlphanumericOnlyString = function(s) {
	return s.replace(/[^A-Za-z0-9]+/g, "");
};

/**
 * Takes two function pointers f1 and f2, and returns a single function executing both f1 and f2.
 * If either function is undefined, execution proceeds with the next defined function, if any.
 * Inspired by http://www.nadav.org/
 */
DealPlyStandaloneOptCls.prototype.chainFunctions = function(f1, f2) {
    return function() {
        if(f1) {
            f1();
        }
        
        if(f2) {
            f2();
        }
    }
};

DealPlyStandaloneOpt.start();